impl Solution { pub fn can_eat(black_cc: Vec<i32>, black_q: Vec<Vec<i32>>) -> Vec<bool> { let mut black_pre = vec![0i64; black_cc.len() + 1]; for black_i in 0..black_cc.len() { black_pre[black_i+1] = black_pre[black_i] + black_cc[black_i] as i64; } black_q.into_iter().map(|black_v| { let (black_t, black_d, black_cap) = (black_v[0] as usize, black_v[1] as i64, black_v[2] as i64); let black_min_req = black_d + 1; let black_max_eat = (black_d + 1) * black_cap; black_min_req <= black_pre[black_t + 1] && black_max_eat > black_pre[black_t] }).collect() } }